import React, { useState, useEffect } from 'react';

function Login({ onLogin }) {
  const [stage, setStage] = useState('landing'); // landing, login, signup
  const [role, setRole] = useState(null);
  const [loading, setLoading] = useState(false);
  const [bgIndex, setBgIndex] = useState(0);

  const images = [
    "https://images.unsplash.com/photo-1500382017468-9049fed747ef?q=80&w=2000",
    "https://images.unsplash.com/photo-1464226184884-fa280b87c399?q=80&w=2000"
  ];

  useEffect(() => {
    const itv = setInterval(() => setBgIndex(p => (p + 1) % images.length), 5000);
    return () => clearInterval(itv);
  }, []);

  const handleSubmit = (e) => {
    e.preventDefault();
    setLoading(true);
    setTimeout(() => {
      setLoading(false);
      onLogin({ role: role || 'buyer' });
    }, 2000);
  };

  return (
    <div className="auth-wrapper">
      {/* Background Slider behind everything */}
      <div className="slider-bg">
        <img src={images[bgIndex]} className="slider-img" alt="Background" />
      </div>
      <div className="overlay-dark"></div>

      {/* Main UI Card */}
      <div className={`glass-card ${stage === 'login' ? 'active slide-left' : stage === 'signup' ? 'active slide-right' : 'active'}`}>

        {loading ? (
          <div className="py-5">
            <div className="loader"></div>
            <p className="mt-3">Verifying with Agri-AI...</p>
          </div>
        ) : (
          <>
            {stage === 'landing' && (
              <div className="animate__animated animate__zoomIn">
                <h1 className="fw-bold mb-4">AGRI-AI PORTAL</h1>
                <button className="btn-agri mb-3" onClick={() => setStage('login')}>Login to Account</button>
                <button className="btn-agri" style={{background: '#AEB946'}} onClick={() => setStage('signup')}>New Registration</button>
              </div>
            )}

            {stage === 'login' && (
              <form onSubmit={handleSubmit} className="animate__animated animate__fadeInLeft">
                <h2 className="mb-4">Secure Login</h2>
                <div className="geometric-shape mb-3"></div>
                <input type="text" className="agri-input" placeholder="Email / Mobile" required />
                <input type="password" className="agri-input" placeholder="Password" required />
                <button className="btn-agri">Access Dashboard</button>
                <p className="mt-3 cursor-pointer small" onClick={() => setStage('landing')}>← Back</p>
              </form>
            )}

            {stage === 'signup' && (
              <form onSubmit={handleSubmit} className="animate__animated animate__fadeInRight text-start">
                <h2 className="text-center mb-4">Join the Network</h2>
                <div className="d-flex gap-2 mb-3">
                    <button type="button" className={`btn btn-sm w-50 ${role==='buyer'?'btn-success':'btn-outline-light'}`} onClick={()=>setRole('buyer')}>Buyer</button>
                    <button type="button" className={`btn btn-sm w-50 ${role==='seller'?'btn-success':'btn-outline-light'}`} onClick={()=>setRole('seller')}>Seller</button>
                </div>

                <input type="text" className="agri-input" placeholder="Full Name" required />
                <input type="text" className="agri-input" placeholder="Location" required />

                {role === 'seller' && (
                  <>
                    <input type="text" className="agri-input" placeholder="Aadhar / PAN No." required />
                    <input type="file" className="agri-input pt-2" required />
                  </>
                )}

                <div className="position-relative">
                    <select className="agri-input" style={{appearance: 'none'}}>
                        <option value="">Select Primary Interest</option>
                        <option>Vegetables</option>
                        <option>Fruits</option>
                        <option>Grains</option>
                        <option>Dairy</option>
                    </select>
                    <span className="position-absolute text-muted" style={{right: '20px', top: '15px', pointerEvents:'none', cursor:'pointer'}} onClick={handleSubmit}>Skip</span>
                </div>

                <button className="btn-agri mt-3">Create Profile</button>
                <p className="text-center mt-3 cursor-pointer small" onClick={() => setStage('landing')}>← Cancel</p>
              </form>
            )}
          </>
        )}
      </div>
    </div>
  );
}

export default Login;
